/**
 * Returns a greeting string based on current time of day
 */
export const getTimeGreeting = () => {
  const hour = new Date().getHours();
  if (hour < 12) return 'Good Morning ☀️';
  if (hour < 17) return 'Good Afternoon ☀️';
  return 'Good Evening 🌙';
};
